import React, { useEffect, useState } from 'react';
import { dashboardAPI } from '../../services/api';
import Card from '../../components/common/Card';
import StatCard from '../../components/common/StatCard';
import { BarChart, Bar, XAxis, YAxis, CartesianGrid, Tooltip, ResponsiveContainer, PieChart, Pie, Cell, Legend } from 'recharts';
import { Users, GraduationCap, AlertTriangle, BookOpen } from 'lucide-react';

const AdminDashboard = () => {
  const [stats, setStats] = useState(null);
  const [loading, setLoading] = useState(true);

  useEffect(() => {
    fetchDashboardData();
  }, []);

  const fetchDashboardData = async () => {
    try {
      const response = await dashboardAPI.getStats();
      if (response.data.success) {
        setStats(response.data.statistics);
      }
    } catch (error) {
      console.error('Error fetching dashboard data:', error);
    } finally {
      setLoading(false);
    }
  };

  if (loading) {
    return <div className="text-center py-10">Loading...</div>;
  }

  const COLORS = ['#3b82f6', '#10b981', '#f59e0b', '#ef4444'];

  return (
    <div className="space-y-6 animate-fade-in">
      {/* Welcome Header */}
      <div className="bg-gradient-to-r from-purple-600 to-purple-700 rounded-xl p-6 text-white">
        <h1 className="text-2xl font-bold mb-1">Admin Dashboard</h1>
        <p className="text-purple-100">System overview and management</p>
      </div>

      {/* Stats Grid */}
      <div className="grid grid-cols-1 md:grid-cols-4 gap-6">
        <StatCard
          title="Total Students"
          value={stats?.totalStudents || 0}
          icon={GraduationCap}
          color="blue"
        />
        <StatCard
          title="Total Faculty"
          value={stats?.totalTeachers || 0}
          icon={Users}
          color="green"
        />
        <StatCard
          title="Capstone Advisers"
          value={stats?.capstoneAdvisersAvailable || 0}
          icon={BookOpen}
          color="purple"
        />
        <StatCard
          title="Pending Violations"
          value={stats?.violationsSummary?.find(v => v.status === 'Pending')?.count || 0}
          icon={AlertTriangle}
          color="orange"
        />
      </div>

      {/* Charts */}
      <div className="grid grid-cols-1 lg:grid-cols-2 gap-6">
        {/* Students per Year Level */}
        <Card title="Students per Year Level">
          <ResponsiveContainer width="100%" height={300}>
            <BarChart data={stats?.studentsPerYear || []}>
              <CartesianGrid strokeDasharray="3 3" />
              <XAxis dataKey="year_level" />
              <YAxis />
              <Tooltip />
              <Bar dataKey="count" fill="#3b82f6" radius={[4, 4, 0, 0]} />
            </BarChart>
          </ResponsiveContainer>
        </Card>

        {/* Violations Summary */}
        <Card title="Violations Summary">
          <ResponsiveContainer width="100%" height={300}>
            <PieChart>
              <Pie
                data={stats?.violationsSummary || []}
                cx="50%"
                cy="50%"
                labelLine={false}
                label={({ status, count }) => `${status}: ${count}`}
                outerRadius={100}
                fill="#8884d8"
                dataKey="count"
                nameKey="status"
              >
                {stats?.violationsSummary?.map((entry, index) => (
                  <Cell key={`cell-${index}`} fill={index === 0 ? '#f59e0b' : '#10b981'} />
                ))}
              </Pie>
              <Tooltip />
            </PieChart>
          </ResponsiveContainer>
        </Card>

        {/* Faculty Employment Status */}
        <Card title="Faculty Employment Status">
          <ResponsiveContainer width="100%" height={300}>
            <PieChart>
              <Pie
                data={stats?.facultyEmployment || []}
                cx="50%"
                cy="50%"
                labelLine={false}
                label={({ employment_status, count }) => `${employment_status}: ${count}`}
                outerRadius={100}
                fill="#8884d8"
                dataKey="count"
                nameKey="employment_status"
              >
                {stats?.facultyEmployment?.map((entry, index) => (
                  <Cell key={`cell-${index}`} fill={COLORS[index % COLORS.length]} />
                ))}
              </Pie>
              <Tooltip />
            </PieChart>
          </ResponsiveContainer>
        </Card>

        {/* Recent Activity */}
        <Card title="Recent Activity">
          <div className="space-y-3 max-h-[300px] overflow-y-auto">
            {stats?.recentActivity?.map((log) => (
              <div key={log.id} className="flex items-start gap-3 py-2 border-b border-secondary-100 last:border-0">
                <div className="w-2 h-2 bg-primary-500 rounded-full mt-2"></div>
                <div className="flex-1">
                  <p className="text-sm text-secondary-800">{log.action}</p>
                  <p className="text-xs text-secondary-500">
                    {log.username || 'System'} • {new Date(log.created_at).toLocaleString()}
                  </p>
                </div>
              </div>
            ))}
            {(!stats?.recentActivity || stats.recentActivity.length === 0) && (
              <p className="text-secondary-500 text-center py-4">No recent activity</p>
            )}
          </div>
        </Card>
      </div>
    </div>
  );
};

export default AdminDashboard;
